class QRScanner {
    constructor(videoElement, onDecode) {
        this.video = videoElement;
        this.onDecode = onDecode;

        // Worker را لود می‌کنیم
        this.worker = new Worker('qr-scanner-worker.min.js');

        this.worker.onmessage = (event) => {
            if (event.data) {
                this.onDecode(event.data);
            }
        };
    }

    async start() {
        // درخواست دوربین
        this.stream = await navigator.mediaDevices.getUserMedia({
            video: { facingMode: "environment" }
        });

        this.video.srcObject = this.stream;
        this.video.setAttribute("playsinline", true);

        // 🔥 مهم‌ترین بخش برای iPhone — باید قبل از play باشد
        await new Promise(resolve => {
            this.video.onloadedmetadata = resolve;
        });

        await this.video.play();

        // شروع حلقه اسکن
        this.scanLoop();
    }

    stop() {
        if (this.stream) {
            this.stream.getTracks().forEach(track => track.stop());
        }
    }

    scanLoop() {
        if (this.video.readyState === this.video.HAVE_ENOUGH_DATA) {
            const canvas = document.createElement("canvas");
            canvas.width = this.video.videoWidth;
            canvas.height = this.video.videoHeight;

            const ctx = canvas.getContext("2d");
            ctx.drawImage(this.video, 0, 0, canvas.width, canvas.height);

            const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

            // ارسال تصویر به Worker برای decode
            this.worker.postMessage(imageData);
        }

        requestAnimationFrame(() => this.scanLoop());
    }
}
